<?php
namespace App\Domain\Accounting\Actions;
use App\Enums\JournalStatus;use App\Models\JournalEntry;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Validation\ValidationException;
class ReverseJournal{public function __construct(private PostJournal $post){}public function execute(JournalEntry $entry,string $reason,string $date):JournalEntry{return DB::transaction(function()use($entry,$reason,$date){$entry=JournalEntry::query()->with('lines')->lockForUpdate()->findOrFail($entry->id);if($entry->status!==JournalStatus::Posted||JournalEntry::query()->where('reversal_of_id',$entry->id)->exists())throw ValidationException::withMessages(['journal'=>['This journal cannot be reversed.']]);$reversal=$this->post->execute(['reversal_of_id'=>$entry->id,'entry_date'=>$date,'source_type'=>JournalEntry::class,'source_id'=>$entry->id,'event_type'=>'journal_reversal','description'=>'Reversal: '.$entry->description,'currency'=>$entry->currency,'metadata'=>['reason'=>$reason],'lines'=>$entry->lines->map(fn($line)=>['ledger_account_id'=>$line->ledger_account_id,'member_id'=>$line->member_id,'loan_id'=>$line->loan_id,'branch_id'=>$line->branch_id,'debit_minor'=>$line->credit_minor,'credit_minor'=>$line->debit_minor,'memo'=>'Reversal of '.$entry->reference,'dimensions'=>$line->dimensions])->all()]);$entry->update(['status'=>JournalStatus::Reversed,'reversed_by'=>Auth::id(),'reversed_at'=>now(),'reversal_reason'=>$reason]);return $reversal;});}}
